const msg = $input.first().json;
const chatId = msg?.message?.chat?.id || msg?.callback_query?.message?.chat?.id;
const userId = msg?.message?.from?.id || msg?.callback_query?.from?.id;
const firstName = msg?.message?.from?.first_name || msg?.callback_query?.from?.first_name || 'Usuario';
const username = msg?.message?.from?.['username'] || msg?.callback_query?.from?.['username'] || msg?.message?.from?.first_name || String(userId) || 'sin_usuario';
const text = msg?.message?.text?.trim() || msg?.callback_query?.data || '';
return [{ json: { chatId, userId: String(userId), username, firstName, text } }];

// ─────────────────────────────────────────────────
// GESTOR DE SESIÓN — lee estado desde Google Sheets
// ─────────────────────────────────────────────────
const extraer = $('🔧 Extraer Datos del Mensaje').first().json;
const text = extraer.text.trim();
const sesion = $json.sesion || '';
let sesionData = {};
try { sesionData = JSON.parse($json.sesion_data || '{}'); } catch(e) {}

// Comandos que siempre resetean la sesión
const resetCmds = ['/start', 'inicio', 'hola', 'menu', '/menu'];
if (resetCmds.includes(text.toLowerCase())) {
  return [{ json: { ...extraer, currentScreen: 'MENU_PRINCIPAL', sesion: '', sesionData: {}, inputText: text, rowNumber: $json.row_number } }];
}

// Si hay sesión activa → continuar wizard
if (sesion === 'ESPERANDO_TIPO')         return [{ json: { ...extraer, currentScreen: 'RECIBIR_TIPO',          sesion, sesionData, inputText: text, rowNumber: $json.row_number } }];
if (sesion === 'ESPERANDO_PRIORIDAD')    return [{ json: { ...extraer, currentScreen: 'RECIBIR_PRIORIDAD',     sesion, sesionData, inputText: text, rowNumber: $json.row_number } }];
if (sesion === 'ESPERANDO_DESCRIPCION')  return [{ json: { ...extraer, currentScreen: 'RECIBIR_DESCRIPCION',  sesion, sesionData, inputText: text, rowNumber: $json.row_number } }];
if (sesion === 'ESPERANDO_CONFIRMACION') return [{ json: { ...extraer, currentScreen: 'RECIBIR_CONFIRMACION', sesion, sesionData, inputText: text, rowNumber: $json.row_number } }];
if (sesion === 'ESPERANDO_TICKET_ID')    return [{ json: { ...extraer, currentScreen: 'RECIBIR_TICKET_ID',    sesion, sesionData, inputText: text, rowNumber: $json.row_number } }];

// Sin sesión → menú normal
const screenMap = { '0':'AYUDA','1':'CREAR_TIPO','2':'CONSULTAR_ESTADO','3':'MIS_SOLICITUDES','4':'REPORTES','5':'CONFIGURACION' };
return [{ json: { ...extraer, currentScreen: screenMap[text] || 'TEXTO_LIBRE', sesion: '', sesionData: {}, inputText: text, rowNumber: $json.row_number } }];

const text = $json.inputText;
const tipoMap = { '1': 'Soporte técnico', '2': 'Solicitud administrativa', '3': 'Consulta general' };

if (text === '9') return [{ json: { ...$json, currentScreen: 'CANCELAR' } }];
if (!tipoMap[text]) return [{ json: { ...$json, currentScreen: 'TIPO_INVALIDO' } }];

const sesionData = { ...($json.sesionData || {}), tipo: tipoMap[text] };
return [{ json: { ...$json, currentScreen: 'TIPO_OK', sesionData } }];

const text = $json.inputText;
const prioMap = { '1': 'Alta', '2': 'Media', '3': 'Baja' };

if (text === '9') return [{ json: { ...$json, currentScreen: 'CANCELAR' } }];
if (!prioMap[text]) return [{ json: { ...$json, currentScreen: 'PRIO_INVALIDA' } }];

const sesionData = { ...($json.sesionData || {}), prioridad: prioMap[text] };
return [{ json: { ...$json, currentScreen: 'PRIO_OK', sesionData } }];

const text = $json.inputText;

if (text === '9') return [{ json: { ...$json, currentScreen: 'CANCELAR' } }];
if (text.length < 10) return [{ json: { ...$json, currentScreen: 'DESC_CORTA' } }];

const sesionData = { ...($json.sesionData || {}), descripcion: text };
return [{ json: { ...$json, currentScreen: 'DESC_OK', sesionData } }];

const sd = $json.sesionData || {};
const ticketId = 'TK-' + Date.now().toString().slice(-6);
const fecha = new Date().toLocaleString('es-CO', { timeZone: 'America/Bogota' });
const sesionData = { ...sd, ticketId, fecha };
return [{ json: { ...$json, sesionData } }];

