const text = $json.inputText;
if (text === '1') return [{ json: { ...$json, currentScreen: 'CONFIRMAR_OK' } }];
return [{ json: { ...$json, currentScreen: 'CANCELAR' } }];

const items = $input.all();
const chatId = $('🔧 Extraer Datos del Mensaje').first().json.chatId;
const nombre = $('🔧 Extraer Datos del Mensaje').first().json.firstName;

const validos = items.filter(i => i.json.id_ticket);
if (validos.length === 0) {
  return [{ json: { chatId, text: `📭 *Mis Solicitudes*\n\nHola ${nombre}, aún no tienes solicitudes.\n\nEscribe /start para volver al menú.` } }];
}

let msg = `📂 *Mis Solicitudes – ${nombre}*\n\n`;
validos.slice(0,10).forEach((item, i) => {
  const t = item.json;
  const e = t.estado==='Abierto'?'🟢':t.estado==='En proceso'?'🟡':'⚫';
  msg += `*${i+1}.* \`${t.id_ticket}\`\n   📌 ${t.tipo}\n   ${e} ${t.estado} | ⚡ ${t.prioridad}\n\n`;
});
msg += 'Escribe /start para volver al menú.';
return [{ json: { chatId, text: msg } }];

const items = $input.all();
const chatId = $('🔧 Extraer Datos del Mensaje').first().json.chatId;
const fecha = new Date().toLocaleDateString('es-CO');
const v = items.filter(i => i.json.id_ticket);
const total = v.length;
const abiertos  = v.filter(i=>i.json.estado==='Abierto').length;
const enProceso = v.filter(i=>i.json.estado==='En proceso').length;
const cerrados  = v.filter(i=>i.json.estado==='Cerrado').length;
const alta  = v.filter(i=>i.json.prioridad==='Alta').length;
const media = v.filter(i=>i.json.prioridad==='Media').length;
const baja  = v.filter(i=>i.json.prioridad==='Baja').length;
const text = `📊 *Reporte General*
📅 _${fecha}_

*Total:* ${total}

*Por estado:*
🟢 Abiertos: ${abiertos}
🟡 En proceso: ${enProceso}
⚫ Cerrados: ${cerrados}

*Por prioridad:*
🔴 Alta: ${alta}
🟡 Media: ${media}
🟢 Baja: ${baja}

Escribe /start para volver al menú.`;
return [{ json: { chatId, text } }];

